import json
with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

def extract(data):
    result = {}
    for proj in data.get('projects', []):
        name = proj['path'].split('/')[-1]
        for fw in proj.get('frameworks', []):
            tfm = fw['framework']
            for pkg in fw.get('topLevelPackages', []):
                key = (name, tfm, pkg['id'])
                result[key] = pkg['resolvedVersion']
    return result

b = extract(baseline)
a = extract(after)
all_keys = sorted(set(b.keys()) | set(a.keys()))

print('CHANGES:')
for k in all_keys:
    bv = b.get(k, 'N/A')
    av = a.get(k, 'N/A')
    if bv != av:
        print(f'  {k[0]:20s} {k[1]:10s} {k[2]:50s} {bv:12s} -> {av}')

print()
print('UNCHANGED:')
for k in all_keys:
    bv = b.get(k, 'N/A')
    av = a.get(k, 'N/A')
    if bv == av:
        print(f'  {k[0]:20s} {k[1]:10s} {k[2]:50s} {bv}')
"", "description": "Compare baseline vs post-CPM packages", "initial_wait": 10}
